<section class="container section"><h1>Actividades</h1><form class="filters"><input type="hidden" name="route" value="activities"><select name="destination"><option value="0">Todos los destinos</option><?php foreach($destinations as $d):?><option value="<?=$d['id']?>" <?=$selected==$d['id']?'selected':''?>><?=Security::e($d['name'])?></option><?php endforeach;?></select><button class="btn small">Filtrar</button></form><div class="grid"><?php foreach($activities as $a):?><article class="card"><img src="<?=Security::e($a['image'])?>"><div class="card-body"><small><?=Security::e($a['destination_name'])?> · <?=Security::e($a['type'])?></small><h3><?=Security::e($a['name'])?></h3><p><?=Security::e($a['description'])?></p><strong>₡<?=number_format($a['price'])?> · <?=Security::e($a['duration'])?></strong></div></article><?php endforeach;?></div></section>
